//     `AUTOMATION_REPOSITORY,` and `CAPTCHA_REPOSITORY,`:
  AUTOMATION_REPOSITORY,
  BRACKET_TOURNAMENT_REPOSITORY,
  CAPTCHA_REPOSITORY,


// ============ 3) Constructor — add ONE new optional param at the very end
//     (right after `guardianRepository`, i.e. immediately before `) {}`
//     at line 902). Uses the same "@Optional + InMemory default" pattern as
//     every other recently-added repo, so it needs ZERO changes to the ~35
//     `new BotUpdateService(...)` call sites in bot-update.service.test.ts. ============

    @Optional()
    @Inject(BRACKET_TOURNAMENT_REPOSITORY)
    private readonly bracketTournamentRepository: BracketTournamentRepository = new InMemoryBracketTournamentRepository(),
  ) {}


// ============ 4) Register the handler in botHandlers() — add this entry
//     right after the existing "giveaway.join" entry (~line 1402-1405),
//     next to poll.command/giveaway.command since it's the same kind of
//     lightweight community-game command. ============

      {
        name: "bracket-tournament.command",
        handle: ({ context, update }) =>
          this.handleBracketTournamentCommand(context, update),
      },


// ============ 5) New handler method — add it right after handlePollVote
//     (~line 7799, same neighborhood as handlePollCommand/handleGiveawayCommand,
//     which it mirrors in style). Handles BOTH commands directly off
//     update.command?.name/args (no dedicated parser module), same
//     "raw name+args" style as handleUtilityPlusCommand. ============

  private async handleBracketTournamentCommand(
    context: FoundationContext,
    update: TelegramUpdateEnvelope,
  ): Promise<BotReply | null> {
    const name = update.command?.name;
    if (name !== "torneo_crear" && name !== "torneo_ganador") {
      return null;
    }

    if (!context.chatId) {
      return { text: "Los torneos se juegan dentro de un grupo." };
    }

    const isAdmin = await this.isActorAdmin(context, update);
    if (!isAdmin) {
      return { text: "Solo un administrador puede gestionar el torneo." };
    }

    const args = update.command?.args ?? [];
    const formatMatches = (matches: readonly { a: string; b: string }[]) =>
      matches.map((match) => `${match.a} vs ${match.b}`).join("\n");

    if (name === "torneo_crear") {
      const entrants = args
        .join(" ")
        .split(",")
        .map((entrant) => entrant.trim())
        .filter((entrant) => entrant.length > 0);

      if (entrants.length < 2) {
        return {
          text: "Uso: /torneo_crear <entrante1, entrante2, ...> (mínimo 2, separados por comas)",
        };
      }

      const existing = await this.bracketTournamentRepository.getOpenTournament(
        context.tenantId,
        context.chatId,
      );
      if (existing) {
        return {
          text: `Ya hay un torneo en curso (ronda ${existing.currentRound}). Avánzalo con /torneo_ganador <nombre> antes de crear otro.`,
        };
      }

      const tournament = await this.bracketTournamentRepository.createTournament(
        context.tenantId,
        context.chatId,
        entrants,
      );

      await this.repository.recordAudit({
        tenantId: context.tenantId,
        actorType: "user",
        action: "bracket-tournament.created",
        resourceType: "bracket-tournament",
        resourceId: tournament.id,
        ...(context.userId ? { actorId: context.userId } : {}),
        payload: { entrants: entrants.length },
      });

      if (tournament.status === "done") {
        // A single entrant is trivially its own champion — no match to play.
        return {
          text: `🏆 Con un único participante, "${tournament.champion}" ya es el campeón.`,
        };
      }

      const byeNote =
        tournament.roundWinners.length > 0
          ? `\n(pase directo: ${tournament.roundWinners.join(", ")})`
          : "";

      return {
        text: `🏆 Torneo creado con ${entrants.length} participantes.\nRonda 1:\n${formatMatches(tournament.pendingMatches)}${byeNote}\n\nUsa /torneo_ganador <nombre> para registrar cada resultado.`,
      };
    }

    // torneo_ganador
    const entrant = args.join(" ").trim();
    if (!entrant) {
      return { text: "Uso: /torneo_ganador <nombre del ganador>" };
    }

    const tournament = await this.bracketTournamentRepository.getOpenTournament(
      context.tenantId,
      context.chatId,
    );
    if (!tournament) {
      return {
        text: "No hay ningún torneo en curso. Empieza uno con /torneo_crear <entrantes separados por comas>.",
      };
    }

    const outcome = await this.bracketTournamentRepository.recordWinner(
      tournament.id,
      entrant,
    );

    if (outcome.kind === "not-found") {
      return { text: "No encuentro ese torneo." };
    }

    if (outcome.kind === "already-done") {
      return {
        text: `Este torneo ya terminó. Campeón: ${outcome.tournament.champion}`,
      };
    }

    if (outcome.kind === "unknown-entrant") {
      return {
        text: `No encuentro a "${entrant}" en los emparejamientos pendientes:\n${formatMatches(outcome.tournament.pendingMatches)}`,
      };
    }

    await this.repository.recordAudit({
      tenantId: context.tenantId,
      actorType: "user",
      action:
        outcome.kind === "champion"
          ? "bracket-tournament.completed"
          : "bracket-tournament.winner-recorded",
      resourceType: "bracket-tournament",
      resourceId: tournament.id,
      ...(context.userId ? { actorId: context.userId } : {}),
      payload: { winner: entrant },
    });

    if (outcome.kind === "champion") {
      return { text: `🏆 ¡${outcome.champion} es el campeón del torneo!` };
    }

    const updated = outcome.tournament;
    if (updated.pendingMatches.length === 0) {
      // Defensive fallback; a completed round always advances or crowns a
      // champion, but never leave the admin with a blank reply.
      return { text: `✅ ${entrant} avanza.` };
    }
    const byeNote =
      updated.roundWinners.length > 0
        ? `\n(pase directo: ${updated.roundWinners.join(", ")})`
        : "";
    return {
      text: `✅ ${entrant} avanza.\nRonda ${updated.currentRound}:\n${formatMatches(updated.pendingMatches)}${byeNote}`,
    };
  }
